100→export function EmojiPickerView() {
101→  const nav = useNavigation();
102→  const [query, setQuery] = useState('');
103→  const [filterValue, setFilterValue] = useState('all');
104→  const [activeIndex, setActiveIndex] = useState(0);
105→  const [actionsOpen, setActionsOpen] = useState(false);
106→  const [recentChars, setRecentChars] = useState<string[]>(loadRecentEmojis);
107→  const { items: hudItems, show: showHUD } = useHUD();
108→  const containerRef = useRef<HTMLDivElement>(null);
109→
110→  const emojiLookup = useMemo(() => {
111→    const map = new Map<string, EmojiEntry>();
112→    for (const e of MOCK_EMOJIS) {
113→      map.set(e.char, e);
114→    }
115→    return map;
116→  }, []);
117→
118→  const recentEmojis = useMemo(
119→    () =>
120→      recentChars
121→        .map(char => emojiLookup.get(char))
122→        .filter((e): e is EmojiEntry => e !== undefined),
123→    [
124→      recentChars,
125→      emojiLookup,
126→    ],
127→  );
128→
129→  const filtered = useMemo(() => {
130→    let emojis = MOCK_EMOJIS;
131→    if (filterValue !== 'all') {
132→      emojis = emojis.filter(e => e.category === filterValue);
133→    }
134→    if (query) {
135→      const lower = query.toLowerCase();
136→      emojis = emojis.filter(
137→        e =>
138→          e.name.toLowerCase().includes(lower) ||
139→          e.keywords.some(k => k.includes(lower)) ||
140→          e.char === query,
141→      );
142→    }
143→    return emojis;
144→  }, [
145→    query,
146→    filterValue,
147→  ]);
148→
149→  const sections = useMemo(() => {
150→    const result: EmojiSection[] = [];
151→
152→    if (!query && filterValue === 'all' && recentEmojis.length > 0) {
153→      result.push({
154→        title: 'Recently Used',
155→        emojis: recentEmojis,
156→      });
157→    }
158→
159→    const grouped = new Map<EmojiCategory, EmojiEntry[]>();
160→    for (const emoji of filtered) {
161→      const existing = grouped.get(emoji.category);
162→      if (existing) {
163→        existing.push(emoji);
164→      } else {
165→        grouped.set(emoji.category, [emoji]);
166→      }
167→    }
168→
169→    for (const cat of EMOJI_CATEGORY_ORDER) {
170→      const items = grouped.get(cat);
171→      if (items && items.length > 0) {
172→        result.push({
173→          title: EMOJI_CATEGORY_LABELS[cat],
174→          emojis: items,
175→        });
176→      }
177→    }
178→
179→    return result;
180→  }, [
181→    filtered,
182→    query,
183→    filterValue,
184→    recentEmojis,
185→  ]);
186→
187→  const flatEmojis = useMemo(() => sections.flatMap(s => s.emojis), [sections]);
188→  const totalCount = flatEmojis.length;
189→
190→  useEffect(() => {
191→    if (totalCount === 0) {
192→      setActiveIndex(0);
193→    } else if (activeIndex >= totalCount) {
194→      setActiveIndex(totalCount - 1);
195→    }
196→  }, [
197→    totalCount,
198→    activeIndex,
199→  ]);
200→
201→  useEffect(() => {
202→    const container = containerRef.current;
203→    if (!container) return;
204→    const el = container.querySelector<HTMLElement>(
205→      `[data-emoji-index="${activeIndex}"]`,
206→    );
207→    el?.scrollIntoView({ block: 'nearest' });
208→  }, [activeIndex]);
209→
210→  const selectedEmoji = flatEmojis[activeIndex];
211→
212→  const addToRecent = useCallback((char: string) => {
213→    setRecentChars(prev => {
214→      const next = [
215→        char,
216→        ...prev.filter(c => c !== char),
217→      ].slice(0, MAX_RECENT);
218→      saveRecentEmojis(next);
219→      return next;
220→    });
221→  }, []);
222→
223→  const handleCopyEmoji = useCallback(
224→    (emoji?: EmojiEntry) => {
225→      const target = emoji ?? selectedEmoji;
226→      if (!target) return;
227→      navigator.clipboard.writeText(target.char).catch(() => {});
228→      setActionsOpen(false);
229→      addToRecent(target.char);
230→      showHUD({
231→        icon: <CopyHUDIcon />,
232→        title: `Copied ${target.char}`,
233→      });
234→    },
235→    [
236→      selectedEmoji,
237→      showHUD,
238→      addToRecent,
239→    ],
240→  );
241→
242→  const handleAction = useCallback(() => {
243→    handleCopyEmoji();
244→  }, [handleCopyEmoji]);
245→
246→  const handleQueryChange = useCallback((value: string) => {
247→    setQuery(value);
248→    setActiveIndex(0);
249→    setActionsOpen(false);
250→  }, []);
251→
252→  const handleFilterChange = useCallback((value: string) => {
253→    setFilterValue(value);
254→    setActiveIndex(0);
255→  }, []);
256→
257→  const toggleActions = useCallback(() => {
258→    setActionsOpen(prev => !prev);
259→  }, []);
260→
261→  const closeActions = useCallback(() => {
262→    setActionsOpen(false);
263→  }, []);
264→
265→  useKeyboardShortcut(
266→    {
267→      key: 'k',
268→      meta: true,
269→    },
270→    toggleActions,
271→  );
272→  useKeyboardShortcut(
273→    {
274→      key: 'c',
275→      meta: true,
276→    },
277→    () => handleCopyEmoji(),
278→  );
279→
280→  useEffect(() => {
281→    function handleKeyDown(e: KeyboardEvent) {
282→      if (totalCount === 0) return;
283→      if (e.metaKey || e.ctrlKey || e.altKey) return;
284→
285→      const isTextInput =
286→        e.target instanceof HTMLInputElement ||
287→        e.target instanceof HTMLTextAreaElement;
288→
289→      switch (e.key) {
290→        case 'ArrowRight': {
291→          if (isTextInput) return;
292→          e.preventDefault();
293→          setActiveIndex(prev => (prev + 1 < totalCount ? prev + 1 : 0));
294→          break;
295→        }
296→        case 'ArrowLeft': {
297→          if (isTextInput) return;
298→          e.preventDefault();
299→          setActiveIndex(prev => (prev - 1 >= 0 ? prev - 1 : totalCount - 1));
300→          break;
301→        }
302→        case 'ArrowDown': {
303→          e.preventDefault();
304→          setActiveIndex(prev => {
305→            const sectionInfo = getSectionInfo(prev);
306→            if (!sectionInfo) return prev;
307→            const { sectionStart, sectionLength } = sectionInfo;
308→            const posInSection = prev - sectionStart;
309→            const row = Math.floor(posInSection / COLUMNS);
310→            const col = posInSection % COLUMNS;
311→            const sectionRows = Math.ceil(sectionLength / COLUMNS);
312→
313→            if (row + 1 < sectionRows) {
314→              const nextIdx = sectionStart + (row + 1) * COLUMNS + col;
315→              return nextIdx < sectionStart + sectionLength
316→                ? nextIdx
317→                : sectionStart + sectionLength - 1;
318→            }
319→
320→            const nextSectionStart = sectionStart + sectionLength;
321→            if (nextSectionStart < totalCount) {
322→              const nextInfo = getSectionInfo(nextSectionStart);
323→              if (!nextInfo) return prev;
324→              const targetIdx = nextSectionStart + col;
325→              return targetIdx < nextSectionStart + nextInfo.sectionLength
326→                ? targetIdx
327→                : nextSectionStart + nextInfo.sectionLength - 1;
328→            }
329→
330→            return prev;
331→          });
332→          break;
333→        }
334→        case 'ArrowUp': {
335→          e.preventDefault();
336→          setActiveIndex(prev => {
337→            const sectionInfo = getSectionInfo(prev);
338→            if (!sectionInfo) return prev;
339→            const { sectionStart } = sectionInfo;
340→            const posInSection = prev - sectionStart;
341→            const row = Math.floor(posInSection / COLUMNS);
342→            const col = posInSection % COLUMNS;
343→
344→            if (row > 0) {
345→              return sectionStart + (row - 1) * COLUMNS + col;
346→            }
347→
348→            if (sectionStart > 0) {
349→              const prevSectionEnd = sectionStart - 1;
350→              const prevInfo = getSectionInfo(prevSectionEnd);
351→              if (!prevInfo) return prev;
352→              const prevSectionRows = Math.ceil(
353→                prevInfo.sectionLength / COLUMNS,
354→              );
355→              const lastRowStart =
356→                prevInfo.sectionStart + (prevSectionRows - 1) * COLUMNS;
357→              const targetIdx = lastRowStart + col;
358→              return targetIdx < prevInfo.sectionStart + prevInfo.sectionLength
359→                ? targetIdx
360→                : prevInfo.sectionStart + prevInfo.sectionLength - 1;
361→            }
362→
363→            return prev;
364→          });
365→          break;
366→        }
367→        case 'Enter': {
368→          e.preventDefault();
369→          handleAction();
370→          break;
371→        }
372→      }
373→    }
374→
375→    window.addEventListener('keydown', handleKeyDown);
376→    return () => window.removeEventListener('keydown', handleKeyDown);
377→  }, [
378→    totalCount,
379→    handleAction,
380→    sections,
381→  ]);
382→
383→  const sectionBoundaries = useMemo(() => {
384→    const boundaries: {
385→      start: number;
386→      length: number;
387→    }[] = [];
388→    let offset = 0;
389→    for (const section of sections) {
390→      boundaries.push({
391→        start: offset,
392→        length: section.emojis.length,
393→      });
394→      offset += section.emojis.length;
395→    }
396→    return boundaries;
397→  }, [sections]);
398→
399→  function getSectionInfo(index: number) {
400→    for (const b of sectionBoundaries) {
401→      if (index >= b.start && index < b.start + b.length) {
402→        return {
403→          sectionStart: b.start,
404→          sectionLength: b.length,
405→        };
406→      }
407→    }
408→    return null;
409→  }
410→
411→  const dropdownSections: DropdownSection[] = useMemo(
412→    () => [
413→      {
414→        title: 'Actions',
415→        actions: [
416→          {
417→            label: 'Copy Emoji',
418→            shortcut: <Kbd keys={['↵']} />,
419→            onClick: () => handleCopyEmoji(),
420→          },
421→          {
422→            label: 'Copy to Clipboard',
423→            shortcut: (
424→              <Kbd
425→                keys={[
426→                  '⌘',
427→                  'C',
428→                ]}
429→              />
430→            ),
431→            onClick: () => handleCopyEmoji(),
432→          },
433→        ],
434→      },
435→    ],
436→    [handleCopyEmoji],
437→  );
438→
439→  const activeDescendantId =
440→    totalCount > 0 ? `emoji-item-${activeIndex}` : undefined;
441→
442→  return (
443→    <>
444→      <SearchBar
445→        value={query}
446→        onChange={handleQueryChange}
447→        placeholder="Search Emoji..."
448→        activeDescendantId={activeDescendantId}
449→        breadcrumbs={nav.breadcrumbs.length > 0 ? nav.breadcrumbs : undefined}
450→        dropdown={
451→          <SearchDropdown
452→            sections={FILTER_SECTIONS}
453→            value={filterValue}
454→            onChange={handleFilterChange}
455→          />
456→        }
457→      />
458→      <div className="command-palette__body">
459→        <div className="command-palette__list-container">
460→          {totalCount === 0 ? (
461→            <EmptyState
462→              icon={<SearchEmptyIcon />}
463→              title="No Emoji Found"
464→              description={
465→                query
466→                  ? 'Try a different search term'
467→                  : 'No emojis in this category'
468→              }
469→            />
470→          ) : (
471→            <div
472→              ref={containerRef}
473→              className="emoji-picker"
474→              role="listbox"
475→              id="emoji-grid"
476→              aria-label="Emoji list"
477→            >
478→              {(() => {
479→                let globalIndex = 0;
480→                return sections.map(section => (
481→                  <div key={section.title} className="emoji-picker__section">
482→                    <div className="emoji-picker__section-header">
483→                      {section.title}
484→                    </div>
485→                    <div className="emoji-picker__grid">
486→                      {section.emojis.map(emoji => {
487→                        const idx = globalIndex++;
488→                        const isActive = idx === activeIndex;
489→                        return (
490→                          <div
491→                            key={`${section.title}-${emoji.char}`}
492→                            id={`emoji-item-${idx}`}
493→                            className={`emoji-picker__cell${isActive ? ' emoji-picker__cell--active' : ''}`}
494→                            role="option"
495→                            aria-selected={isActive}
496→                            aria-label={emoji.name}
497→                            data-emoji-index={idx}
498→                            onClick={() => {
499→                              setActiveIndex(idx);
500→                              handleCopyEmoji(emoji);
501→                            }}
502→                            onMouseEnter={() => setActiveIndex(idx)}
503→                          >
504→                            {emoji.char}
505→                          </div>
506→                        );
507→                      })}
508→                    </div>
509→                  </div>
510→                ));
511→              })()}
512→            </div>
513→          )}
514→        </div>
515→      </div>
516→      <ActionPanel
517→        contextLabel="Emoji"
518→        actions={[
519→          {
520→            label: selectedEmoji ? `Copy ${selectedEmoji.char}` : 'Copy Emoji',
521→            shortcut: <Kbd keys={['↵']} />,
522→          },
523→          {
524→            label: 'Actions',
525→            shortcut: (
526→              <Kbd
527→                keys={[
528→                  '⌘',
529→                  'K',
530→                ]}
531→              />
532→            ),
533→            onClick: toggleActions,
534→          },
535→        ]}
536→        dropdownOpen={actionsOpen}
537→        dropdownSections={dropdownSections}
538→        onDropdownClose={closeActions}
539→      />
540→      <HUDContainer items={hudItems} />
541→    </>
542→  );
543→}
